INSERT INTO therapists (id, name, title, bio, image_url) VALUES
(1, 'Dr. Aisha Rahman', 'Clinical Psychologist & Islamic Counselor', 'Dr. Aisha Rahman is a licensed clinical psychologist with over 8 years of experience in mental health counseling. She specializes in integrating Islamic principles with evidence-based therapeutic approaches.', 'https://images.unsplash.com/photo-1559839734-2b71ea197ec2?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1170&q=80'),
(2, 'Imam Khalid Hassan', 'Islamic Scholar & Spiritual Guide', 'Imam Khalid Hassan serves as both a spiritual leader and mental health counselor, bringing together traditional Islamic knowledge with modern psychological understanding.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1170&q=80'),
(3, 'Dr. Fatima Al-Zahra', 'Marriage & Family Therapist', 'Dr. Fatima Al-Zahra is a licensed marriage and family therapist who specializes in helping Muslim families navigate relationship challenges while honoring Islamic values.', 'https://images.unsplash.com/photo-1594824804732-ca8db723f8fa?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1170&q=80');
